	@Test
	void statementPatternPlanningEstimateUsesPlanningCardinalityPath() throws IOException {
		ValueStore valueStore = mock(ValueStore.class);
		TripleStore tripleStore = mock(TripleStore.class);
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		org.eclipse.rdf4j.model.IRI subject = vf.createIRI("urn:test:s");
		org.eclipse.rdf4j.model.IRI predicate = vf.createIRI("urn:test:p");
		org.eclipse.rdf4j.model.IRI object = vf.createIRI("urn:test:o");
		StatementPattern pattern = new StatementPattern(new Var("s", subject), new Var("p", predicate),
				new Var("o", object));
		when(valueStore.getId(subject)).thenReturn(1L);
		when(valueStore.getId(predicate)).thenReturn(2L);
		when(valueStore.getId(object)).thenReturn(3L);
		when(tripleStore.getDataRevision()).thenReturn(7L);
		when(tripleStore.planningCardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID)).thenReturn(42.0d);
		when(tripleStore.cardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID)).thenReturn(99.0d);

		LmdbStatementPatternCardinalitySource source = new LmdbStatementPatternCardinalitySource(valueStore,
				tripleStore);

		assertEquals(42.0d, source.estimateForPlanning(pattern));
		verify(tripleStore).planningCardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID);
		verify(tripleStore, never()).cardinality(1L, 2L, 3L, LmdbValue.UNKNOWN_ID);
	}

